public static void main(Args _args)
{
    SalesAgreementId currSalesAgreementId;
    FormRun callerForm = _args.caller();

    if(callerForm is FormRun && formHasMethod(callerForm, identifierStr("getSalesAgreementId")))
    {
        currSalesAgreementId = callerForm.getSalesAgreementId();
    }

    ETG_ImportDataExcel::getInsertDataSalesContarct(ETG_ImportDataExcel::getImportExcel(), currSalesAgreementId);
}
